using System;
using System.Reflection;
using System.Linq;
using System.Collections.Generic;

var dllPaths = new[] {
    System.IO.Path.Expand("~/.nuget/packages/microsoft.agents.ai/1.0.0/lib/net10.0/Microsoft.Agents.AI.dll"),
    System.IO.Path.Expand("~/.nuget/packages/microsoft.extensions.ai.abstractions/10.4.1/lib/net10.0/Microsoft.Extensions.AI.Abstractions.dll"),
    System.IO.Path.Expand("~/.nuget/packages/microsoft.extensions.ai.openai/10.4.1/lib/net10.0/Microsoft.Extensions.AI.OpenAI.dll"),
};

foreach (var dllPath in dllPaths)
{
    var actualPath = dllPath.Replace("~", System.Environment.GetEnvironmentVariable("HOME"));
    Console.WriteLine($"\n\n{'='*80}");
    Console.WriteLine($"ASSEMBLY: {System.IO.Path.GetFileName(actualPath)}");
    Console.WriteLine($"{'='*80}\n");

    if (!System.IO.File.Exists(actualPath))
    {
        Console.WriteLine($"File not found: {actualPath}");
        continue;
    }

    try
    {
        var assembly = Assembly.LoadFrom(actualPath);
        var types = assembly.GetExportedTypes().OrderBy(t => t.FullName);

        foreach (var type in types)
        {
            if (type.IsPublic)
            {
                Console.WriteLine($"\n{type.FullName}");

                // Show constructors
                var ctors = type.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
                if (ctors.Length > 0)
                {
                    Console.WriteLine("  Constructors:");
                    foreach (var ctor in ctors)
                    {
                        var @params = string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
                        Console.WriteLine($"    .ctor({@params})");
                    }
                }

                // Show methods
                var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly)
                    .Where(m => !m.IsSpecialName)
                    .OrderBy(m => m.Name);

                if (methods.Any())
                {
                    Console.WriteLine("  Methods:");
                    foreach (var method in methods)
                    {
                        var returnType = method.ReturnType.Name;
                        var @params = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
                        var isStatic = method.IsStatic ? "static " : "";
                        Console.WriteLine($"    {isStatic}{returnType} {method.Name}({@params})");
                    }
                }

                // Show properties
                var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly);
                if (props.Length > 0)
                {
                    Console.WriteLine("  Properties:");
                    foreach (var prop in props.OrderBy(p => p.Name))
                    {
                        var getter = prop.GetGetMethod() != null ? "get" : "";
                        var setter = prop.GetSetMethod() != null ? "set" : "";
                        var access = $"{getter}{(getter != "" && setter != "" ? ", " : "")}{setter}";
                        Console.WriteLine($"    {prop.PropertyType.Name} {prop.Name} [{access}]");
                    }
                }
            }
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"Error: {ex.Message}");
    }
}
