import xml.etree.ElementTree as ET
import re

def extract_methods(xml_file, type_filter):
    tree = ET.parse(xml_file)
    root = tree.getroot()

    results = {}

    for member in root.findall(".//member"):
        name = member.get('name', '')

        # Match types
        if not name.startswith('T:'):
            continue

        if type_filter not in name:
            continue

        type_name = name.replace('T:', '')
        results[type_name] = {'summary': '', 'members': []}

        summary = member.find('.//summary')
        if summary is not None:
            results[type_name]['summary'] = (summary.text or '').strip()

    # Now get methods for matched types
    for member in root.findall(".//member"):
        name = member.get('name', '')

        if not name.startswith('M:'):
            continue

        # Check if this method belongs to one of our types
        for type_key in results.keys():
            if name.startswith(f'M:{type_key}.'):
                summary = member.find('.//summary')
                summary_text = (summary.text or '').strip() if summary is not None else ''

                # Extract method name and params
                method_sig = name.replace(f'M:{type_key}.', '')

                results[type_key]['members'].append({
                    'name': method_sig,
                    'summary': summary_text[:80]
                })

    return results

# Extract from both files
