## 4. INVOKING/RUNNING AN AGENT

### Namespace
`Microsoft.Agents.AI`

### Agent Invocation Methods

**BASE CLASS: AIAgent**
```csharp
public abstract class AIAgent
{
    // Run once (single invocation)
    public Task<AgentResponse> RunAsync(
        AgentSession session,
        AgentRunOptions? options = null,
        CancellationToken cancellationToken = default
    );

    // Run with input message (creates list internally)
    public Task<AgentResponse> RunAsync(
        string input,
        AgentSession session,
        AgentRunOptions? options = null,
        CancellationToken cancellationToken = default
    );

    public Task<AgentResponse> RunAsync(
        ChatMessage message,
        AgentSession session,
        AgentRunOptions? options = null,
        CancellationToken cancellationToken = default
    );

    public Task<AgentResponse> RunAsync(
        IEnumerable<ChatMessage> messages,
        AgentSession session,
        AgentRunOptions? options = null,
        CancellationToken cancellationToken = default
    );

    // Streaming variants
    public IAsyncEnumerable<AgentResponseUpdate> RunStreamingAsync(
        AgentSession session,
        AgentRunOptions? options = null,
        CancellationToken cancellationToken = default
    );

    public IAsyncEnumerable<AgentResponseUpdate> RunStreamingAsync(
        string input,
        AgentSession session,
        AgentRunOptions? options = null,
        CancellationToken cancellationToken = default
    );

    public IAsyncEnumerable<AgentResponseUpdate> RunStreamingAsync(
        ChatMessage message,
        AgentSession session,
        AgentRunOptions? options = null,
        CancellationToken cancellationToken = default
    );

    public IAsyncEnumerable<AgentResponseUpdate> RunStreamingAsync(
        IEnumerable<ChatMessage> messages,
        AgentSession session,
        AgentRunOptions? options = null,
        CancellationToken cancellationToken = default
    );

    // Generic typed return (deserialize to type T)
    public Task<AgentResponse<T>> RunAsync<T>(
        AgentSession session,
        JsonSerializerOptions? jsonSerializerOptions = null,
        AgentRunOptions? options = null,
        CancellationToken cancellationToken = default
    );
}
```

