        invoker: (args) => MyClass.MyMethod(args.GetArgument<string>("arg1")),
        options: null
    )
}
```

---

## 3. Invoke Agent (All Variants)

```csharp
// Single string input
var response = await agent.RunAsync(
    input: "Hello agent",
    session: session,
    options: runOptions,
    cancellationToken: CancellationToken.None
);

// ChatMessage input
var response = await agent.RunAsync(
    message: new ChatMessage(ChatRole.User, "Hello"),
    session: session,
    options: runOptions
);

// Multiple messages
var response = await agent.RunAsync(
    messages: new[]
    {
        new ChatMessage(ChatRole.System, "You are helpful"),
        new ChatMessage(ChatRole.User, "Help me")
    },
    session: session,
    options: runOptions
);

// Empty invocation (continues conversation)
var response = await agent.RunAsync(
    session: session,
    options: runOptions
);

// With generic return (deserialize to type)
var response = await agent.RunAsync<MyResultType>(
    session: session,
    options: runOptions
);
```

---

## 4. Streaming Invocation

```csharp
// Streaming variant - returns IAsyncEnumerable<AgentResponseUpdate>
await foreach (var update in agent.RunStreamingAsync(
    input: "Stream this",
    session: session,
    options: runOptions
))
{
    if (update.Message != null)
        Console.WriteLine($"Message: {update.Message.Text}");

    if (update.FunctionCall != null)
        Console.WriteLine($"Tool: {update.FunctionCall.FunctionName}");

    if (update.FunctionResult != null)
        Console.WriteLine($"Result: {update.FunctionResult.Result}");
}
```

